use std::collections::HashSet;

fn solve(s: String) -> Vec<String> {
    let mut existing = HashSet::new();
    let mut segments = Vec::new();
    let s: Vec<u8> = s.into_bytes();
    let mut current_start = 0;
    while current_start < s.len() {
        let mut current_segment = String::new();
        let mut i = current_start;
        while i < s.len() {
            current_segment.push(s[i] as char);
            if !existing.contains(&current_segment) {
                existing.insert(current_segment.clone());
                segments.push(current_segment);
                current_start = i + 1;
                break;
            } else {
                i += 1;
            }
        }
    }
    segments
}
